#include <stdio.h>
#include <stdlib.h>

// Define the structure for a tree node
typedef struct TreeNode {
    int val;
    struct TreeNode* left;
    struct TreeNode* right;
} TreeNode;

// Function to find the inorder predecessor and successor
void findPredecessorAndSuccessor(TreeNode* root, TreeNode* p, TreeNode** predecessor, TreeNode** successor) {
    // Initialize predecessor and successor
    *predecessor = NULL;
    *successor = NULL;

    // Perform inorder traversal
    TreeNode* current = root;
    TreeNode* stack[100000];
    int top = -1;
    while (current || top >= 0) {
        while (current) {
            stack[++top] = current;
            current = current->left;
        }
        current = stack[top--];
        if (*predecessor == NULL && current->val < p->val) {
            *predecessor = current;
        }
        if (current == p) {
            // Find the successor
            if (current->right) {
                TreeNode* temp = current->right;
                while (temp->left) {
                    temp = temp->left;
                }
                *successor = temp;
            }
        }
        if (*successor == NULL && current->val > p->val) {
            *successor = current;
            break;
        }
        current = current->right;
    }
}

int main() {
    // Create the BST
    TreeNode* root = (TreeNode*)malloc(sizeof(TreeNode));
    root->val = 5;
    root->left = (TreeNode*)malloc(sizeof(TreeNode));
    root->left->val = 3;
    root->left->left = (TreeNode*)malloc(sizeof(TreeNode));
    root->left->left->val = 2;
    root->left->right = (TreeNode*)malloc(sizeof(TreeNode));
    root->left->right->val = 4;
    root->right = (TreeNode*)malloc(sizeof(TreeNode));
    root->right->val = 7;
    root->right->left = NULL;
    root->right->right = NULL;
    root->left->left->left = NULL;
    root->left->left->right = NULL;
    root->left->right->left = NULL;
    root->left->right->right = NULL;

    // Find the inorder predecessor and successor
    TreeNode* p = root->left;
    TreeNode* predecessor = NULL;
    TreeNode* successor = NULL;
    findPredecessorAndSuccessor(root, p, &predecessor, &successor);

    // Print the result
    printf("Predecessor: %d\n", predecessor ? predecessor->val : -1);
    printf("Successor: %d\n", successor ? successor->val : -1);

    return 0;
}

