import java.util.Stack;

// Define the structure for a tree node
public class TreeNode {
    int val;
    TreeNode left;
    TreeNode right;
    TreeNode(int x) { val = x; }
}

public class Solution {
    // Function to find the inorder predecessor and successor
    public void findPredecessorAndSuccessor(TreeNode root, TreeNode p, TreeNode[] predecessor, TreeNode[] successor) {
        // Initialize predecessor and successor
        predecessor[0] = null;
        successor[0] = null;

        // Perform inorder traversal
        Stack<TreeNode> stack = new Stack<>();
        TreeNode current = root;
        while (current != null || !stack.isEmpty()) {
            while (current != null) {
                stack.push(current);
                current = current.left;
            }
            current = stack.pop();
            if (predecessor[0] == null && current.val < p.val) {
                predecessor[0] = current;
            }
            if (current == p) {
                // Find the successor
                if (current.right != null) {
                    TreeNode temp = current.right;
                    while (temp.left != null) {
                        temp = temp.left;
                    }
                    successor[0] = temp;
                }
            }
            if (successor[0] == null && current.val > p.val) {
                successor[0] = current;
                break;
            }
            current = current.right;
        }
    }

    public static void main(String[] args) {
        // Create the BST
        TreeNode root = new TreeNode(5);
        root.left = new TreeNode(3);
        root.left.left = new TreeNode(2);
        root.left.right = new TreeNode(4);
        root.right = new TreeNode(7);

        // Find the inorder predecessor and successor
        TreeNode p = root.left;
        TreeNode[] predecessor = new TreeNode[1];
        TreeNode[] successor = new TreeNode[1];
        new Solution().findPredecessorAndSuccessor(root, p, predecessor, successor);

        // Print the result
        System.out.println("Predecessor: " + (predecessor[0] != null ? predecessor[0].val : "NULL"));
        System.out.println("Successor: " + (successor[0] != null ? successor[0].val : "NULL"));
    }
}

